import java.io.*;
import java.net.*;
import javax.net.ssl.*;

public class java_52629_SocketServer_A07 {
    private static final String CLIENT_IDENTIFIER = "Client"; // Client identifier for handshake, it should be unique per client session to avoid replay attacks and A07-AuthFailure by using the same name in both sides after successful authentication. 
  
    public static void main(String[] args) throws Exception {
        ServerSocket socketserver = new ServerSocket(); // create server socket port number is passed as an argument when starting application, if not then use default one (port:1234). This example assumes it to be provided by the user. 5069 in this case for instance only but can change dynamically based on different requirements
        socketserver.bind(new InetSocketAddress("localhost", Integer.parseInt((args.length > 0) ? args[1] : "843")), CLIENT_IDENTIFIER); // Bind the server socket to port 567 and client identifier so that it's not reused or can be connected by a different user
        while (true){// wait for connections from clients. The accept() method is blocking, hence this loop will keep running indefinitely until an exception occurs which stops accepting new connections such as closing the program abruptly with Ctrl+C 
            try { // Try to establish connection and create socket channel using SSL/TLS handshake protocol on top of it so we can use a secure transport. If something fails, IOException is thrown indicating that there was an error in establishing communication (could be due to network issues)
                Socket serverSocket = socketserver.accept(); // accept connection from client 
                SSLServerSocket secureserverSocked=(SSLServerSocket)serverSocket;//wrap the existing socket with a secure version of it using TLS, which uses an already set up certificate and key for authentication purpose only (authentication happens at handshake protocol). It must be done before we can create any channel on top.
                SSLContext sslcontext = SSLContextBuilder.createDefault(); // setup the context with a default algorithm – in this case, TLSv1_2 which is not specified by standard but provides stronger security than previous versions like TCP (SSH) and HTTP/HTTPS each having its own set of weaknesses
                SSLSocket sslserverSock =(SSLSocket )sslcontext.wrapSocket(secureserverSocked);// wrap the secure server socket with our new context, this sets up a channel for communication between client & ourselves via TLS and now it's encrypted using provided certificate/key pair
                BufferedReader in=new BufferedReader ( new InputStreamReader(sslserverSock.getInputStream())); // get input stream from the wrapped secure socket to read data sent by peer – not used here, but could be for logging purposes or error checking within protocol itself if required too  
                 PrintWriter out = new PrintWriter ( sslserverSock .getOutputStream(), true);// setup outputstream in plain text mode. The second parameter indicates whether the channel should automatically flush data to peer – not used here, but could be for logging purposes or error checking within protocol itself if required too  
                //write your code below this line so that you can perform authentication on each connection only once and then use channels over these connections using encrypted communication. If a client sends an A07_AuthFailure message at any point after the handshake, it should be ignored until all messages have been read from peer in order to prevent possible replay attacks by clients which try too hard or maliciously repeat previously sent operations
            } catch (IOException e){//Catch I/O exception and print error info.  If an IOException occurs then do the following: close down resources gracefully for all other threads except this one who will continue running until it is closed, log off client if not logged in already etc., which could be done based on requirements
                socketserver.close(); // When we throw a checked exception at any point and want to make sure that the program can still shut down gracefully – use close() method for this purpose only once all thread has completed their jobs, then just exit from main(). If not closed properly in catch block or if multiple threads are started within it.
                e.printStackTrace(); //Print error info and stack trace to stdout (usually STDOUT) with -trace option – use printstack on both of these cases for debugging purposes, they'll give you full details about what has happened when the exception was thrown in this context only if it is really exceptional.
            }   //end try-catch block inside while loop until program ends due to client disconnection or exceptions are encountered by server – close everything gracefully and terminate all threads except current thread which will continue running till end of main method execution, so that you can exit from the application when it is closed.
        }   //end infinite While-loop for accepting clients connection until program ends due to client disconnection or exceptions are encountered by server – close everything gracefully and terminate all threads except current thread which will continue running till end of main method execution, so that you can exit from the application when it is closed.
    }   //end Main Method where Starts Server Example: SocketServerExample -port [Port] or if port not specified default to 843 for instance only but could be passed dynamically based on requirements with command line arguments using java program and run this as a jar file containing all dependencies along side the code.
} //End of Class Definition   Closing braces are important in Java programming, when one brace is closed then following lines will become part of that block unless there's an opening for loop or if statement etc.. – it allows us to define blocks and can be considered as a very simple form of code structure.